Here are the public test cases for feature1_capability_validation:
{
  "description": "Validate a requested capability set before a session starts. The validator accepts a configuration that names at least one launch target (an application file path, an installed package identifier, or a supported browser) and is case-insensitive about the platform name. It rejects a configuration that names no launch target, names an unsupported browser, or names both an application file and a browser at the same time. A valid configuration outputs valid=true; a rejected one outputs a neutral error category plus any offending value.",
  "cases": [
    {
      "input": {
        "op": "validate_capabilities",
        "caps": {
          "platformName": "Android",
          "deviceName": "device",
          "app": "/path/to/some.apk"
        }
      },
      "expected_output": "valid=true\n"
    },
    {
      "input": {
        "op": "validate_capabilities",
        "caps": {
          "platformName": "Android",
          "deviceName": "device"
        }
      },
      "expected_output": "error=missing_required_capability\nrequired=app_or_package_or_browser\n"
    },
    {
      "input": {
        "op": "validate_capabilities",
        "caps": {
          "platformName": "Android",
          "deviceName": "device",
          "browserName": "Netscape Navigator"
        }
      },
      "expected_output": "error=unsupported_browser\nbrowser=Netscape Navigator\n"
    },
    {
      "input": {
        "op": "validate_capabilities",
        "caps": {
          "platformName": "Android",
          "deviceName": "device",
          "app": "/path/to/some.apk",
          "browserName": "Chrome"
        }
      },
      "expected_output": "error=conflicting_capabilities\nconflict=app_and_browser\n"
    }
  ]
}

Here are the public test cases for feature2_1_proxy_active:
{
  "description": "Report whether request proxying to an external in-app web engine is currently active. Until such an engine is attached, proxying is inactive, so this query returns proxy_active=false.",
  "cases": [
    {
      "input": {
        "op": "proxy_config",
        "query": "proxy_active"
      },
      "expected_output": "proxy_active=false\n"
    }
  ]
}

Here are the public test cases for feature2_3_proxy_avoid_list:
{
  "description": "Expose the list of HTTP method + URL-pattern pairs that must never be proxied to an external web engine and are always handled locally. Each pair names a method and a route regular expression. The list covers context switching, vendor-specific extension endpoints, touch performance endpoints, and orientation endpoints.",
  "cases": [
    {
      "input": {
        "op": "proxy_config",
        "query": "avoid_list"
      },
      "expected_output": "avoid_route method=POST pattern=^\\/session\\/[^/]+\\/context\navoid_route method=GET pattern=^\\/session\\/[^/]+\\/context\navoid_route method=POST pattern=^\\/session\\/[^/]+\\/appium\navoid_route method=GET pattern=^\\/session\\/[^/]+\\/appium\navoid_route method=POST pattern=^\\/session\\/[^/]+\\/touch\\/perform\navoid_route method=POST pattern=^\\/session\\/[^/]+\\/touch\\/multi\\/perform\navoid_route method=POST pattern=^\\/session\\/[^/]+\\/orientation\navoid_route method=GET pattern=^\\/session\\/[^/]+\\/orientation\n"
    }
  ]
}

Here are the public test cases for feature3_1_parse_touch_absolute:
{
  "description": "Normalize a touch gesture sequence given in absolute screen coordinates into a list of resolved touch states. Each press/moveTo/tap/longPress state carries an absolute x/y; a moveTo expressed relative to the previous position is accumulated onto the running position; a wait state inherits the current position; and a release state carries no coordinates. The output lists each state in order with its resolved coordinates.",
  "cases": [
    {
      "input": {
        "op": "parse_touch",
        "actions": [
          {
            "action": "press",
            "options": {
              "x": 100,
              "y": 101
            }
          },
          {
            "action": "moveTo",
            "options": {
              "x": 50,
              "y": 51
            }
          },
          {
            "action": "wait",
            "options": {
              "ms": 5000
            }
          },
          {
            "action": "moveTo",
            "options": {
              "x": -40,
              "y": -41
            }
          },
          {
            "action": "release",
            "options": {}
          }
        ]
      },
      "expected_output": "action=press x=100 y=101\naction=moveTo x=150 y=152\naction=wait x=150 y=152\naction=moveTo x=110 y=111\naction=release\n"
    }
  ]
}

Here are the public test cases for feature3_3_gesture_routing:
{
  "description": "Route a gesture to the correct underlying device command name depending on whether it is scoped to a specific element or applied at screen level. A swipe, flick, or drag scoped to an element emits an element-prefixed command; the same gesture without an element emits the bare command. The output is the resolved command name.",
  "cases": [
    {
      "input": {
        "op": "gesture_route",
        "gesture": "swipe",
        "scoped": true
      },
      "expected_output": "command=element:swipe\n"
    },
    {
      "input": {
        "op": "gesture_route",
        "gesture": "swipe",
        "scoped": false
      },
      "expected_output": "command=swipe\n"
    },
    {
      "input": {
        "op": "gesture_route",
        "gesture": "flick",
        "scoped": true
      },
      "expected_output": "command=element:flick\n"
    },
    {
      "input": {
        "op": "gesture_route",
        "gesture": "flick",
        "scoped": false
      },
      "expected_output": "command=flick\n"
    },
    {
      "input": {
        "op": "gesture_route",
        "gesture": "drag",
        "scoped": true
      },
      "expected_output": "command=element:drag\n"
    },
    {
      "input": {
        "op": "gesture_route",
        "gesture": "drag",
        "scoped": false
      },
      "expected_output": "command=drag\n"
    }
  ]
}

Here are the public test cases for feature4_1_get_network_connection:
{
  "description": "Compute the current network connection state as a bitmask from three independent device signals: airplane mode (bit value 1), WiFi (bit value 2), and mobile data (bit value 4). When airplane mode is on the result is 1 and the WiFi and data bits are not added. Otherwise the result is the sum of the WiFi and data bits that are on. The output is the integer connection value.",
  "cases": [
    {
      "input": {
        "op": "get_network",
        "airplane": false,
        "wifi": false,
        "data": false
      },
      "expected_output": "connection=0\n"
    },
    {
      "input": {
        "op": "get_network",
        "airplane": true,
        "wifi": false,
        "data": false
      },
      "expected_output": "connection=1\n"
    },
    {
      "input": {
        "op": "get_network",
        "airplane": false,
        "wifi": true,
        "data": false
      },
      "expected_output": "connection=2\n"
    },
    {
      "input": {
        "op": "get_network",
        "airplane": false,
        "wifi": false,
        "data": true
      },
      "expected_output": "connection=4\n"
    },
    {
      "input": {
        "op": "get_network",
        "airplane": false,
        "wifi": true,
        "data": true
      },
      "expected_output": "connection=6\n"
    }
  ]
}

Here are the public test cases for feature4_2_set_network_connection:
{
  "description": "Apply a requested network connection state given as a bitmask, decoding it into ordered device operations. The lowest bit selects airplane mode, the next bit WiFi, the next bit data. The system always sets and broadcasts airplane mode first. When airplane mode is requested on, it stops there and does not touch WiFi/data. When airplane mode is off, it then applies the WiFi and data flags together. The output lists each device operation in order with its arguments.",
  "cases": [
    {
      "input": {
        "op": "set_network",
        "type": 0
      },
      "expected_output": "device_op=set_airplane_mode value=0\ndevice_op=broadcast_airplane_mode value=0\ndevice_op=set_wifi_and_data wifi=0 data=0\n"
    },
    {
      "input": {
        "op": "set_network",
        "type": 1
      },
      "expected_output": "device_op=set_airplane_mode value=1\ndevice_op=broadcast_airplane_mode value=1\n"
    },
    {
      "input": {
        "op": "set_network",
        "type": 2
      },
      "expected_output": "device_op=set_airplane_mode value=0\ndevice_op=broadcast_airplane_mode value=0\ndevice_op=set_wifi_and_data wifi=1 data=0\n"
    },
    {
      "input": {
        "op": "set_network",
        "type": 4
      },
      "expected_output": "device_op=set_airplane_mode value=0\ndevice_op=broadcast_airplane_mode value=0\ndevice_op=set_wifi_and_data wifi=0 data=1\n"
    },
    {
      "input": {
        "op": "set_network",
        "type": 6
      },
      "expected_output": "device_op=set_airplane_mode value=0\ndevice_op=broadcast_airplane_mode value=0\ndevice_op=set_wifi_and_data wifi=1 data=1\n"
    }
  ]
}

Here are the public test cases for feature4_3_toggle_location_services:
{
  "description": "Toggle the device location-services setting by opening the relevant settings screen and emitting a platform-dependent key navigation sequence to move focus onto the toggle. Platforms at API level 16 use the sequence 19,19,20 (up, up, down). Platforms at API level 19 and above use 22,22,19 (right, right, up) and additionally send one preparatory up keyevent (19) before opening the screen. Platforms at API level 15 and below have no global toggle and report a not_implemented error.",
  "cases": [
    {
      "input": {
        "op": "toggle_location",
        "apiLevel": 15
      },
      "expected_output": "error=not_implemented\n"
    },
    {
      "input": {
        "op": "toggle_location",
        "apiLevel": 16
      },
      "expected_output": "setting=LOCATION_SOURCE_SETTINGS\nkey_sequence=19,19,20\n"
    },
    {
      "input": {
        "op": "toggle_location",
        "apiLevel": 19
      },
      "expected_output": "pre_keyevent=19\nsetting=LOCATION_SOURCE_SETTINGS\nkey_sequence=22,22,19\n"
    }
  ]
}

Here are the public test cases for feature5_1_ensure_device_locale:
{
  "description": "Ensure the device language and country match a requested target, performing the minimum device operations needed and rebooting only when something changed. When neither language nor country is requested, nothing happens. On platforms below API level 23, language and country are independent settings: only the ones that differ from the current value are written, and a reboot follows any change. On platforms at API level 23 and above the value is a single combined locale (lowercase-language + dash + uppercase-country): it is rewritten only if it differs, followed by a reboot. The output lists each device operation in order, or no_change when nothing was needed.",
  "cases": [
    {
      "input": {
        "op": "ensure_locale",
        "current": {
          "apiLevel": 18
        }
      },
      "expected_output": "no_change=true\n"
    },
    {
      "input": {
        "op": "ensure_locale",
        "language": "en",
        "country": "us",
        "current": {
          "apiLevel": 18,
          "language": "en",
          "country": "us"
        }
      },
      "expected_output": "no_change=true\n"
    },
    {
      "input": {
        "op": "ensure_locale",
        "language": "en",
        "country": "us",
        "current": {
          "apiLevel": 18,
          "language": "fr",
          "country": "FR"
        }
      },
      "expected_output": "device_op=set_language value=en\ndevice_op=set_country value=us\ndevice_op=reboot\n"
    },
    {
      "input": {
        "op": "ensure_locale",
        "language": "en",
        "country": "us",
        "current": {
          "apiLevel": 23,
          "locale": "en-US"
        }
      },
      "expected_output": "no_change=true\n"
    },
    {
      "input": {
        "op": "ensure_locale",
        "language": "en",
        "country": "us",
        "current": {
          "apiLevel": 23,
          "locale": "fr-FR"
        }
      },
      "expected_output": "device_op=set_locale value=en-US\ndevice_op=reboot\n"
    }
  ]
}

Here are the public test cases for feature5_3_device_info_from_caps:
{
  "description": "Resolve which connected device to use and report its identifier and emulator port. When a specific device identifier is requested it must appear in the connected device list, otherwise a device_not_found error is reported along with the requested identifier. When no identifier is requested, the first connected device is chosen. When a virtual device name is requested, the running emulator's identifier and port are used. The output gives the resolved udid and emulator_port.",
  "cases": [
    {
      "input": {
        "op": "device_info",
        "caps": {
          "udid": "emulator-1234"
        },
        "devices": [
          {
            "udid": "emulator-1234"
          },
          {
            "udid": "rotalume-1337"
          }
        ],
        "emulatorPort": 1234
      },
      "expected_output": "udid=emulator-1234\nemulator_port=1234\n"
    },
    {
      "input": {
        "op": "device_info",
        "caps": {},
        "devices": [
          {
            "udid": "emulator-1234"
          },
          {
            "udid": "rotalume-1337"
          }
        ],
        "emulatorPort": 1234
      },
      "expected_output": "udid=emulator-1234\nemulator_port=1234\n"
    },
    {
      "input": {
        "op": "device_info",
        "caps": {
          "avd": "AVD_NAME"
        },
        "devices": [
          {
            "udid": "emulator-1234"
          },
          {
            "udid": "rotalume-1337"
          }
        ],
        "emulatorPort": 1234
      },
      "expected_output": "udid=emulator-1234\nemulator_port=1234\n"
    },
    {
      "input": {
        "op": "device_info",
        "caps": {
          "udid": "foomulator"
        },
        "devices": [
          {
            "udid": "emulator-1234"
          },
          {
            "udid": "rotalume-1337"
          }
        ],
        "emulatorPort": 1234
      },
      "expected_output": "error=device_not_found\nudid=foomulator\n"
    }
  ]
}

Here are the public test cases for feature5_5_java_version:
{
  "description": "Detect the installed Java runtime version from the raw banner text a Java toolchain prints. The parser scans for a line containing a Java or OpenJDK version banner and extracts the version token. When the banner is recognized, the version is reported; when it cannot be recognized, the operation reports a neutral java_version_unavailable error.",
  "cases": [
    {
      "input": {
        "op": "java_version",
        "raw": "java version \"1.8.0_40\""
      },
      "expected_output": "java_version=1.8.0_40\n"
    },
    {
      "input": {
        "op": "java_version",
        "raw": "foo bar"
      },
      "expected_output": "error=java_version_unavailable\n"
    }
  ]
}

Here are the public test cases for feature6_1_remote_apk_path:
{
  "description": "Compute the canonical on-device staging path for a cached application archive from its content hash. The path is the device temporary directory followed by the hash and an .apk suffix.",
  "cases": [
    {
      "input": {
        "op": "remote_apk_path",
        "md5": "foo"
      },
      "expected_output": "remote_path=/data/local/tmp/foo.apk\n"
    }
  ]
}

Here are the public test cases for feature7_1_get_strings:
{
  "description": "Return the localized application strings for a requested language. When the requested language is already cached, the cached map is returned without extracting again. When no language is requested, the device's current language is used to select the cached map. When the language is not cached, the strings are freshly extracted and returned. The output lists each string key=value pair.",
  "cases": [
    {
      "input": {
        "op": "get_strings",
        "scenario": "fresh",
        "language": "en",
        "strings": {
          "test": "en_value"
        }
      },
      "expected_output": "test=en_value\n"
    },
    {
      "input": {
        "op": "get_strings",
        "scenario": "cached",
        "language": "fr",
        "deviceLanguage": "en",
        "cache": {
          "en": {
            "test": "en_value"
          },
          "fr": {
            "test": "fr_value"
          }
        }
      },
      "expected_output": "test=fr_value\n"
    },
    {
      "input": {
        "op": "get_strings",
        "scenario": "cached",
        "deviceLanguage": "en",
        "cache": {
          "en": {
            "test": "en_value"
          },
          "fr": {
            "test": "fr_value"
          }
        }
      },
      "expected_output": "test=en_value\n"
    }
  ]
}

Here are the public test cases for feature7_3_remove_null_properties:
{
  "description": "Remove properties whose value is null or undefined from an object, while keeping properties whose value is falsy-but-defined such as false or 0. The output lists the remaining keys in order and their count.",
  "cases": [
    {
      "input": {
        "op": "remove_null_properties",
        "object": {
          "foo": null,
          "bar": true
        }
      },
      "expected_output": "remaining_keys=bar\nkey_count=1\n"
    },
    {
      "input": {
        "op": "remove_null_properties",
        "object": {
          "foo": false,
          "bar": true,
          "zero": 0
        }
      },
      "expected_output": "remaining_keys=foo,bar,zero\nkey_count=3\n"
    }
  ]
}

Here are the public test cases for feature8_1_get_contexts:
{
  "description": "Enumerate the automation contexts currently available. The native context is always present and listed first. When the session targets an in-app web engine browser, the web engine context is also listed. Otherwise the available web views are discovered from the device and appended. The output lists the contexts as a comma-separated set.",
  "cases": [
    {
      "input": {
        "op": "get_contexts",
        "browser": "Chrome"
      },
      "expected_output": "contexts=NATIVE_APP,CHROMIUM\n"
    },
    {
      "input": {
        "op": "get_contexts",
        "webviews": []
      },
      "expected_output": "contexts=NATIVE_APP\n"
    }
  ]
}

Here are the public test cases for feature9_session_teardown:
{
  "description": "Tear down a session, performing only the device operations appropriate to its options and in a fixed order. If the session was never started (already shut down), nothing is done beyond noting that. Otherwise, when the unicode keyboard was enabled with keyboard reset and a default input method was recorded, the input method is restored first. A non-web session is force-stopped, then the device is sent to its home screen. When full reset is requested, the application is additionally uninstalled. The output lists each device operation in order.",
  "cases": [
    {
      "input": {
        "op": "session_teardown",
        "alreadyShutDown": true
      },
      "expected_output": "already_shut_down=true\n"
    },
    {
      "input": {
        "op": "session_teardown",
        "opts": {}
      },
      "expected_output": "device_op=force_stop\ndevice_op=go_to_home\n"
    },
    {
      "input": {
        "op": "session_teardown",
        "opts": {
          "fullReset": true
        }
      },
      "expected_output": "device_op=force_stop\ndevice_op=go_to_home\ndevice_op=uninstall_apk\n"
    },
    {
      "input": {
        "op": "session_teardown",
        "opts": {
          "unicodeKeyboard": true,
          "resetKeyboard": true
        },
        "defaultIME": "someDefaultIME"
      },
      "expected_output": "device_op=set_ime value=someDefaultIME\ndevice_op=force_stop\ndevice_op=go_to_home\n"
    }
  ]
}
